components.css:
.ds-btn { display: inline-flex; align-items: center; justify-content: center; gap: 8px; font-family: 'Pretendard Variable', 'Pretendard', sans-serif; font-weight: 500; font-size: 0.9375rem; line-height: 1.3; height: 40px; padding: 0 16px; border: 0; border-radius: var(--radius-lg, 14px); cursor: pointer; user-select: none; transition: background 140ms cubic-bezier(0.2,0,0,1), color 140ms cubic-bezier(0.2,0,0,1), box-shadow 140ms cubic-bezier(0.2,0,0,1), transform 140ms cubic-bezier(0.2,0,0,1); }
.ds-btn--primary { background: var(--color-primary, #5a6f4f); color: var(--color-primary-fg, #ffffff); box-shadow: var(--shadow-sm, 0 1px 2px rgba(26,24,20,0.04)); }
.ds-btn--primary:hover { background: var(--color-primary-hover, #4a5f3f); }
.ds-btn--primary:active { background: var(--color-primary-active, #3a4b32); transform: scale(0.98); }
.ds-btn--primary:focus-visible { outline: 2px solid var(--color-primary, #5a6f4f); outline-offset: 2px; }
.ds-btn--primary:disabled { opacity: 0.5; cursor: not-allowed; }

.ds-btn--ghost { background: transparent; color: var(--color-fg, #1a1814); box-shadow: none; font-family: 'Pretendard Variable', 'Pretendard', sans-serif; font-weight: 500; font-size: 0.9375rem; height: 40px; padding: 0 16px; border: 0; border-radius: var(--radius-lg, 14px); display: inline-flex; align-items: center; justify-content: center; gap: 8px; cursor: pointer; transition: background 140ms cubic-bezier(0.2,0,0,1), transform 140ms cubic-bezier(0.2,0,0,1); }
.ds-btn--ghost:hover { background: var(--color-bg-subtle, #f1eee7); }
.ds-btn--ghost:active { transform: scale(0.98); }
.ds-btn--ghost:focus-visible { outline: 2px solid var(--color-primary, #5a6f4f); outline-offset: 2px; }

.ds-chip { display: inline-flex; align-items: center; gap: 6px; height: 36px; padding: 0 14px; font-family: 'Pretendard Variable', 'Pretendard', sans-serif; font-size: 0.875rem; font-weight: 500; border-radius: var(--radius-pill, 9999px); background: var(--color-bg-elevated, #ffffff); color: var(--color-fg, #1a1814); border: 1px solid var(--color-border, #e5e0d5); cursor: pointer; transition: background 140ms cubic-bezier(0.2,0,0,1), color 140ms cubic-bezier(0.2,0,0,1), border-color 140ms cubic-bezier(0.2,0,0,1); }
.ds-chip:hover { border-color: var(--color-border-strong, #c8c1b3); }
.ds-chip--selected { background: var(--color-fg, #1a1814); color: var(--color-bg, #faf8f4); border-color: transparent; }
.ds-chip:focus-visible { outline: 2px solid var(--color-primary, #5a6f4f); outline-offset: 2px; }

.ds-card { border-radius: var(--radius-xl, 18px); background: var(--color-bg-elevated, #ffffff); border: 1px solid var(--color-border, #e5e0d5); box-shadow: none; overflow: hidden; }
.ds-card--interactive { transition: transform 240ms cubic-bezier(0.2,0,0,1), box-shadow 240ms cubic-bezier(0.2,0,0,1); cursor: pointer; }
.ds-card--interactive:hover { transform: translateY(-2px); box-shadow: var(--shadow-md, 0 4px 12px rgba(26,24,20,0.08)); }
.ds-card__body { padding: 24px; }
.ds-card__title { margin: 0; font-family: 'Pretendard Variable', 'Pretendard', sans-serif; font-size: 1.0625rem; font-weight: 600; line-height: 1.3; color: var(--color-fg, #1a1814); }
.ds-card__meta { margin: 6px 0 0; font-size: 0.8125rem; letter-spacing: 0.01em; color: var(--color-fg-muted, #67604f); }

.ds-field { display: block; }
.ds-field__label { display: block; margin-bottom: 6px; font-family: 'Pretendard Variable', 'Pretendard', sans-serif; font-size: 0.875rem; font-weight: 500; color: var(--color-fg, #1a1814); }
.ds-field__helper { display: block; margin-top: 6px; font-size: 0.75rem; color: var(--color-fg-subtle, #847b6a); }
.ds-input { display: flex; align-items: center; gap: 8px; height: 44px; padding: 0 14px; border-radius: var(--radius-lg, 14px); background: var(--color-bg-elevated, #ffffff); border: 1px solid var(--color-border, #e5e0d5); transition: border-color 140ms cubic-bezier(0.2,0,0,1), box-shadow 140ms cubic-bezier(0.2,0,0,1); }
.ds-input:focus-within { border-color: var(--color-primary, #5a6f4f); box-shadow: 0 0 0 2px var(--color-primary-soft, #e8eee5); }
.ds-input__el { width: 100%; border: 0; outline: none; background: transparent; font-family: 'Pretendard Variable', 'Pretendard', sans-serif; font-size: 0.9375rem; color: var(--color-fg, #1a1814); }
.ds-input__el::placeholder { color: var(--color-fg-subtle, #847b6a); }

.ds-badge { display: inline-flex; align-items: center; gap: 6px; padding: 4px 10px; border-radius: var(--radius-pill, 9999px); font-family: 'Pretendard Variable', 'Pretendard', sans-serif; font-size: 0.75rem; font-weight: 500; line-height: 1; }
.ds-badge--primary { background: var(--color-primary-soft, #e8eee5); color: var(--color-primary, #5a6f4f); }
.ds-badge--accent { background: var(--color-accent-soft, #ffe5d2); color: var(--color-accent, #c97550); }
.ds-badge__dot { width: 6px; height: 6px; border-radius: 9999px; background: currentColor; }

.ds-cal { font-family: 'Pretendard Variable', 'Pretendard', sans-serif; color: var(--color-fg, #1a1814); }
.ds-cal__month { margin-bottom: 8px; font-size: 0.875rem; font-weight: 500; color: var(--color-fg-muted, #67604f); }
.ds-cal__grid { display: grid; grid-template-columns: repeat(7, 1fr); gap: 4px; text-align: center; }
.ds-cal__wd { font-size: 10px; font-weight: 600; padding-bottom: 4px; color: var(--color-fg-muted, #67604f); }
.ds-cal__wd--sun { color: var(--color-error, #b33a3a); }
.ds-cal__wd--sat { color: var(--color-primary, #5a6f4f); }
.ds-cal__day { position: relative; aspect-ratio: 1 / 1; border: 0; border-radius: var(--radius-md, 10px); font-size: 0.75rem; background: transparent; color: var(--color-fg-subtle, #847b6a); cursor: pointer; transition: background 140ms cubic-bezier(0.2,0,0,1), color 140ms cubic-bezier(0.2,0,0,1); }
.ds-cal__day--muted { opacity: 0.4; cursor: default; }
.ds-cal__day--open { background: var(--color-primary-soft, #e8eee5); color: var(--color-fg, #1a1814); font-weight: 600; }
.ds-cal__day--open:hover { background: var(--color-primary, #5a6f4f); color: var(--color-primary-fg, #ffffff); }
.ds-cal__day--selected { background: var(--color-primary, #5a6f4f); color: var(--color-primary-fg, #ffffff); font-weight: 700; }
.ds-cal__dot { position: absolute; bottom: 4px; left: 50%; transform: translateX(-50%); width: 4px; height: 4px; border-radius: 9999px; background: var(--color-primary, #5a6f4f); }
.ds-cal__day--open:hover .ds-cal__dot { background: var(--color-primary-fg, #ffffff); }
.ds-cal__slots { margin-top: 12px; display: flex; flex-wrap: wrap; gap: 6px; }
.ds-cal__slot { display: inline-flex; align-items: center; gap: 4px; padding: 4px 10px; border: 0; border-radius: var(--radius-pill, 9999px); background: var(--color-bg-subtle, #f1eee7); color: var(--color-fg, #1a1814); font-size: 11px; font-weight: 500; cursor: pointer; transition: background 140ms cubic-bezier(0.2,0,0,1), color 140ms cubic-bezier(0.2,0,0,1); }
.ds-cal__slot:hover { background: var(--color-primary-soft, #e8eee5); color: var(--color-primary, #5a6f4f); }
.ds-cal__slot:focus-visible, .ds-cal__day:focus-visible { outline: 2px solid var(--color-primary, #5a6f4f); outline-offset: 2px; }

.ds-addon { font-family: 'Pretendard Variable', 'Pretendard', sans-serif; color: var(--color-fg, #1a1814); }
.ds-addon__head { display: flex; align-items: center; gap: 6px; margin-bottom: 8px; font-size: 0.875rem; font-weight: 500; }
.ds-addon__spark { color: var(--color-accent, #c97550); }
.ds-addon__row { display: flex; align-items: center; gap: 8px; padding: 10px; border: 1px solid var(--color-border, #e5e0d5); border-radius: var(--radius-lg, 14px); transition: background 140ms cubic-bezier(0.2,0,0,1); }
.ds-addon__row--active { background: var(--color-primary-soft, #e8eee5); }
.ds-addon__info { min-width: 0; flex: 1; }
.ds-addon__name { font-size: 0.875rem; font-weight: 500; }
.ds-addon__price { font-size: 11px; color: var(--color-fg-muted, #67604f); }
.ds-addon__sub { color: var(--color-primary, #5a6f4f); font-weight: 500; }
.ds-addon__stepper { display: flex; align-items: center; gap: 4px; flex-shrink: 0; }
.ds-addon__btn { display: grid; place-items: center; width: 28px; height: 28px; border-radius: 9999px; border: 1px solid var(--color-border, #e5e0d5); background: transparent; color: var(--color-fg, #1a1814); cursor: pointer; transition: background 140ms cubic-bezier(0.2,0,0,1); }
.ds-addon__btn:hover { background: var(--color-bg-subtle, #f1eee7); }
.ds-addon__btn:focus-visible { outline: 2px solid var(--color-primary, #5a6f4f); outline-offset: 2px; }
.ds-addon__qty { width: 20px; text-align: center; font-size: 0.875rem; font-weight: 600; font-variant-numeric: tabular-nums; }

.ds-spacecard { display: block; text-decoration: none; color: var(--color-fg, #1a1814); font-family: 'Pretendard Variable', 'Pretendard', sans-serif; }
.ds-spacecard__media { position: relative; aspect-ratio: 4 / 3; border-radius: var(--radius-xl, 18px); overflow: hidden; background: var(--color-bg-subtle, #f1eee7); }
.ds-spacecard__img { position: absolute; inset: 0; background: linear-gradient(135deg, var(--color-primary-soft, #e8eee5), var(--color-bg-subtle, #f1eee7)); transition: transform 420ms cubic-bezier(0.2,0,0,1); }
.ds-spacecard:hover .ds-spacecard__img { transform: scale(1.04); }
.ds-spacecard__fav { position: absolute; top: 12px; right: 12px; display: inline-flex; align-items: center; justify-content: center; width: 36px; height: 36px; border: 0; border-radius: 9999px; background: rgba(26, 24, 20, 0.3); backdrop-filter: blur(4px); cursor: pointer; transition: transform 140ms cubic-bezier(0.2,0,0,1); }
.ds-spacecard__fav:hover { transform: scale(1.05); }
.ds-spacecard__fav:focus-visible { outline: 2px solid var(--color-primary, #5a6f4f); outline-offset: 2px; }
.ds-spacecard__body { margin-top: 12px; display: flex; flex-direction: column; gap: 6px; }
.ds-spacecard__meta { font-size: 0.8125rem; letter-spacing: 0.01em; color: var(--color-fg-muted, #67604f); }
.ds-spacecard__title { margin: 0; font-size: 1rem; font-weight: 600; line-height: 1.3; }
.ds-spacecard:hover .ds-spacecard__title { text-decoration: underline; text-underline-offset: 4px; text-decoration-thickness: 1px; }
.ds-spacecard__slot { display: inline-flex; align-items: center; gap: 4px; align-self: flex-start; padding: 2px 8px; border-radius: 9999px; background: var(--color-accent-soft, #ffe5d2); color: var(--color-accent, #c97550); font-size: 11px; font-weight: 600; }
.ds-spacecard__price { font-size: 0.875rem; font-weight: 600; }
.ds-spacecard__price-num { color: var(--color-primary, #5a6f4f); }
